#include "controller.h"

#include <string.h>

static void controller_set_safe_idle(controller_t *controller)
{
    if (controller == NULL) {
        return;
    }

    controller->inlet_open = false;
    controller->heater_on = false;
    controller->state = CONTROLLER_STATE_SAFE_IDLE;
}

void controller_init(controller_t *controller)
{
    if (controller == NULL) {
        return;
    }

    controller_set_safe_idle(controller);
    controller->has_valid_temperature = false;
    controller->previous_temperature_c = 0;
    controller->last_temperature_c = 0;
    controller->last_temperature_ms = 0U;
    controller->has_valid_level = false;
    controller->last_level = 0;
    controller->last_level_ms = 0U;
}

static bool controller_is_sensor_timeout(const controller_t *controller, uint32_t now_ms)
{
    if (controller == NULL) {
        return true;
    }

    if (!controller->has_valid_temperature || !controller->has_valid_level) {
        return false;
    }

    const uint32_t temp_age = now_ms - controller->last_temperature_ms;
    const uint32_t level_age = now_ms - controller->last_level_ms;

    return (temp_age > CONTROLLER_SENSOR_TIMEOUT_MS) || (level_age > CONTROLLER_SENSOR_TIMEOUT_MS);
}

static bool controller_is_temperaturerising(const controller_t *controller, int current_temp, int previous_temp)
{
    if (controller == NULL) {
        return false;
    }

    return (current_temp > previous_temp);
}

controller_output_t controller_step(controller_t *controller, controller_input_t input)
{
    controller_output_t output = {
        .inlet_open = false,
        .heater_on = false,
        .state = CONTROLLER_STATE_SAFE_IDLE,
        .state_name = controller_state_name(CONTROLLER_STATE_SAFE_IDLE),
        .changed = false,
        .timed_out = false,
    };
    bool previous_inlet_open;
    bool previous_heater_on;
    controller_state_t previous_state;

    if (controller == NULL) {
        return output;
    }

    previous_inlet_open = controller->inlet_open;
    previous_heater_on = controller->heater_on;
    previous_state = controller->state;

    /* Check for sensor timeout first - forces safe state */
    if (input.kind == CONTROLLER_INPUT_SENSOR_TIMEOUT) {
        controller_set_safe_idle(controller);
        output.timed_out = true;
        goto done;
    }

    /* Handle malformed input - invalid temp or level forces safe state */
    if (input.kind == CONTROLLER_INPUT_INVALID_TEMPERATURE ||
        input.kind == CONTROLLER_INPUT_INVALID_LEVEL) {
        controller_set_safe_idle(controller);
        output.timed_out = true;
        goto done;
    }

    /* Handle timeout check - if sensors are stale, go to safe state */
    if (controller_is_sensor_timeout(controller, input.now_ms)) {
        controller_set_safe_idle(controller);
        output.timed_out = true;
        goto done;
    }

    /* Update sensor freshness based on valid input type */
    switch (input.kind) {
    case CONTROLLER_INPUT_NONE:
        /* No new sensor data - check if we need to timeout */
        break;
    case CONTROLLER_INPUT_TEMPERATURE:
        controller->has_valid_temperature = true;
        controller->previous_temperature_c = controller->last_temperature_c;
        controller->last_temperature_c = input.temperature_c;
        controller->last_temperature_ms = input.now_ms;
        break;
    case CONTROLLER_INPUT_LEVEL:
        controller->has_valid_level = true;
        controller->last_level = input.level;
        controller->last_level_ms = input.now_ms;
        break;
    default:
        /* Unknown input type - safe state */
        controller_set_safe_idle(controller);
        output.timed_out = true;
        goto done;
    }

    /* Stay in safe all-off state until both sensors have been seen validly */
    if (!controller->has_valid_temperature || !controller->has_valid_level) {
        controller_set_safe_idle(controller);
        goto done;
    }

    /* Control policy implementation */
    const int level = controller->last_level;
    const int temp = controller->last_temperature_c;
    bool inlet_should_open = false;
    bool heater_should_be_on = false;
    controller_state_t new_state = CONTROLLER_STATE_SAFE_IDLE;

    /* Heater guard: if level < 55, keep heater OFF */
    if (level < CONTROLLER_MIN_HEATING_LEVEL) {
        inlet_should_open = false;
        heater_should_be_on = false;
        new_state = CONTROLLER_STATE_SAFE_IDLE;
        goto apply_output;
    }

    /* Low level: open inlet, heater off */
    if (level < CONTROLLER_FILL_LEVEL_THRESHOLD) {
        inlet_should_open = true;
        heater_should_be_on = false;
        new_state = CONTROLLER_STATE_FILLING;
        goto apply_output;
    }

    /* High level: close inlet */
    if (level > CONTROLLER_LEVEL_HIGH_THRESHOLD) {
        inlet_should_open = false;
        new_state = CONTROLLER_STATE_SAFE_IDLE;
        goto apply_output;
    }

    /* Working level region: 60 <= LEVEL <= 75 */
    if (level >= CONTROLLER_FILL_LEVEL_THRESHOLD && level <= CONTROLLER_LEVEL_HIGH_THRESHOLD) {
        /* Temperature-based decisions in working region */
        if (temp < CONTROLLER_TEMP_LOW_THRESHOLD) {
            /* Low temperature: close inlet, turn heater ON */
            inlet_should_open = false;
            heater_should_be_on = true;
            new_state = CONTROLLER_STATE_HEATING;
            goto apply_output;
        } else if (temp >= CONTROLLER_TEMP_LOW_THRESHOLD && temp < CONTROLLER_TEMP_EARLY_OFF_THRESHOLD) {
            /* 45 <= TEMP < 47: close inlet, hold previous safe heater state */
            inlet_should_open = false;
            heater_should_be_on = controller->heater_on;
            new_state = CONTROLLER_STATE_HOLDING;
            goto apply_output;
        } else if (temp >= CONTROLLER_TEMP_EARLY_OFF_THRESHOLD && temp <= CONTROLLER_TEMP_HIGH_THRESHOLD) {
            /* 47 <= TEMP <= 48: check for early heater off */
            bool was_rising = controller_is_temperaturerising(controller, temp, controller->previous_temperature_c);
            if (was_rising) {
                inlet_should_open = false;
                heater_should_be_on = false;
                new_state = CONTROLLER_STATE_HOLDING;
            } else {
                inlet_should_open = false;
                heater_should_be_on = controller->heater_on;
                new_state = CONTROLLER_STATE_HOLDING;
            }
            goto apply_output;
        } else if (temp > CONTROLLER_TEMP_HIGH_THRESHOLD) {
            /* TEMP > 48: close inlet, turn heater OFF */
            inlet_should_open = false;
            heater_should_be_on = false;
            new_state = CONTROLLER_STATE_HOLDING;
            goto apply_output;
        } else {
            /* Default safe state for unexpected temp in working region */
            inlet_should_open = false;
            heater_should_be_on = controller->heater_on;
            new_state = CONTROLLER_STATE_HOLDING;
            goto apply_output;
        }
    }

apply_output:
    controller->inlet_open = inlet_should_open;
    controller->heater_on = heater_should_be_on;
    controller->state = new_state;

done:
    output.inlet_open = controller->inlet_open;
    output.heater_on = controller->heater_on;
    output.state = controller->state;
    output.state_name = controller_state_name(controller->state);
    output.changed =
        (previous_inlet_open != controller->inlet_open) ||
        (previous_heater_on != controller->heater_on) ||
        (previous_state != controller->state);
    return output;
}

const char *controller_state_name(controller_state_t state)
{
    switch (state) {
    case CONTROLLER_STATE_FILLING:
        return "STATE FILLING";
    case CONTROLLER_STATE_HEATING:
        return "STATE HEATING";
    case CONTROLLER_STATE_HOLDING:
        return "STATE HOLDING";
    case CONTROLLER_STATE_SAFE_IDLE:
    default:
        return "STATE SAFE_IDLE";
    }
}

