    controller->state = CONTROLLER_STATE_SAFE_IDLE;
}

void controller_init(controller_t *controller)
{
    if (controller == NULL) {
        return;
    }

    controller_set_safe_idle(controller);
    controller->has_valid_temperature = false;
    controller->previous_temperature_c = 0;
    controller->last_temperature_c = 0;
    controller->last_temperature_ms = 0U;
    controller->has_valid_level = false;
    controller->last_level = 0;
    controller->last_level_ms = 0U;
}

static bool controller_is_sensor_timeout(const controller_t *controller, uint32_t now_ms)
{
    if (controller == NULL) {
        return true;
    }

    if (!controller->has_valid_temperature || !controller->has_valid_level) {
        return false;
    }

    const uint32_t temp_age = now_ms - controller->last_temperature_ms;
    const uint32_t level_age = now_ms - controller->last_level_ms;

    return (temp_age > CONTROLLER_SENSOR_TIMEOUT_MS) || (level_age > CONTROLLER_SENSOR_TIMEOUT_MS);
}

static bool controller_is_temperaturerising(const controller_t *controller, int current_temp, int previous_temp)
{
    if (controller == NULL) {
        return false;
    }

    return (current_temp > previous_temp);
}

/* Determine the desired actuator state based on current sensor readings */
static void controller_compute_desired_state(controller_t *controller)
{
    if (controller == NULL) {
        return;
    }

    const int level = controller->last_level;
    const int temp = controller->last_temperature_c;
    bool inlet_should_open = false;
    bool heater_should_be_on = false;
    controller_state_t new_state = CONTROLLER_STATE_SAFE_IDLE;

    /* Low level: open inlet, heater off */
    if (level < CONTROLLER_FILL_LEVEL_THRESHOLD) {
        inlet_should_open = true;
        heater_should_be_on = false;
        new_state = CONTROLLER_STATE_FILLING;
        return;
    }

    /* Heater guard: if level < 55, keep heater OFF (only applies when level >= 60) */
    if (level < CONTROLLER_MIN_HEATING_LEVEL) {
        inlet_should_open = false;
        heater_should_be_on = false;
        new_state = CONTROLLER_STATE_SAFE_IDLE;
        return;
    }

    /* High level: close inlet */
    if (level > CONTROLLER_LEVEL_HIGH_THRESHOLD) {
        inlet_should_open = false;
        new_state = CONTROLLER_STATE_SAFE_IDLE;
        return;
    }

    /* Working level region: 60 <= LEVEL <= 75 */
    if (level >= CONTROLLER_FILL_LEVEL_THRESHOLD && level <= CONTROLLER_LEVEL_HIGH_THRESHOLD) {
        /* Temperature-based decisions in working region */
        if (temp < CONTROLLER_TEMP_LOW_THRESHOLD) {
            /* Low temperature: close inlet, turn heater ON */
            inlet_should_open = false;
            heater_should_be_on = true;
            new_state = CONTROLLER_STATE_HEATING;

        return;
    }

    /* Working level region: 60 <= LEVEL <= 75 */
    if (level >= CONTROLLER_FILL_LEVEL_THRESHOLD && level <= CONTROLLER_LEVEL_HIGH_THRESHOLD) {
        /* Temperature-based decisions in working region */
        if (temp < CONTROLLER_TEMP_LOW_THRESHOLD) {
            /* Low temperature: close inlet, turn heater ON */
            inlet_should_open = false;
            heater_should_be_on = true;
            new_state = CONTROLLER_STATE_HEATING;
            return;
        } else if (temp >= CONTROLLER_TEMP_LOW_THRESHOLD && temp < CONTROLLER_TEMP_EARLY_OFF_THRESHOLD) {
            /* 45 <= TEMP < 47: close inlet, hold previous safe heater state */
            inlet_should_open = false;
            heater_should_be_on = controller->heater_on;
            new_state = CONTROLLER_STATE_HOLDING;
            return;
        } else if (temp >= CONTROLLER_TEMP_EARLY_OFF_THRESHOLD && temp <= CONTROLLER_TEMP_HIGH_THRESHOLD) {
            /* 47 <= TEMP <= 48: check for early heater off */
            bool was_rising = controller_is_temperaturerising(controller, temp, controller->previous_temperature_c);
            if (was_rising) {
                inlet_should_open = false;
                heater_should_be_on = false;
                new_state = CONTROLLER_STATE_HOLDING;
            } else {
                inlet_should_open = false;
                heater_should_be_on = controller->heater_on;
                new_state = CONTROLLER_STATE_HOLDING;
            }
            return;
        } else if (temp > CONTROLLER_TEMP_HIGH_THRESHOLD) {
            /* TEMP > 48: close inlet, turn heater OFF */
            inlet_should_open = false;
            heater_should_be_on = false;
            new_state = CONTROLLER_STATE_HOLDING;
            return;
        } else {
            /* Default safe state for unexpected temp in working region */
            inlet_should_open = false;
            heater_should_be_on = controller->heater_on;
            new_state = CONTROLLER_STATE_HOLDING;
            return;
        }
    }

    /* Fallback - should not happen with valid inputs */
    controller_set_safe_idle(controller);
}

