{
    char *end = NULL;
    long parsed;

    if ((token == NULL) || (level == NULL)) {
        return false;
    }

    parsed = strtol(token, &end, 10);
    if ((end == token) || (*end != '\0')) {
        return false;
    }

    if ((parsed < 0L) || (parsed > 100L)) {
        return false;
    }

    *level = (int) parsed;
    return true;
